const payload = $input.item.json;
const script = payload.script;

// A thread is represented as an array of tweet strings.
// A single post is a plain string.
// Handle the case where script was stored as JSON string (serialised array).
let resolvedScript = script;
if (typeof script === 'string') {
  try {
    const parsed = JSON.parse(script);
    if (Array.isArray(parsed)) {
      resolvedScript = parsed;
    }
  } catch (_) {
    // Remains a plain string
  }
}

const isThread = Array.isArray(resolvedScript);

return [{
  json: {
    content_piece_id: payload.content_piece_id,
    script: resolvedScript,
    isThread
  }
}];

// X API v2 — post a thread via OAuth 1.0a
// Env vars: X_API_KEY, X_API_SECRET, X_ACCESS_TOKEN, X_ACCESS_TOKEN_SECRET

const crypto = require('crypto');

const credentials = {
  apiKey: $env.X_API_KEY,
  apiSecret: $env.X_API_SECRET,
  accessToken: $env.X_ACCESS_TOKEN,
  accessTokenSecret: $env.X_ACCESS_TOKEN_SECRET,
};

const tweets = $input.item.json.script; // array of strings
const X_TWEETS_URL = 'https://api.twitter.com/2/tweets';

function percentEncode(value) {
  return encodeURIComponent(value)
    .replace(/!/g, '%21')
    .replace(/'/g, '%27')
    .replace(/\(/g, '%28')
    .replace(/\)/g, '%29')
    .replace(/\*/g, '%2A');
}

function generateNonce() {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  let nonce = '';
  for (let i = 0; i < 32; i++) {
    nonce += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return nonce;
}

function buildAuthHeader(method, url, creds) {
  const nonce = generateNonce();
  const timestamp = Math.floor(Date.now() / 1000).toString();

  const oauthParams = {
    oauth_consumer_key: creds.apiKey,
    oauth_nonce: nonce,
    oauth_signature_method: 'HMAC-SHA1',
    oauth_timestamp: timestamp,
    oauth_token: creds.accessToken,
    oauth_version: '1.0',
  };

  const paramString = Object.keys(oauthParams)
    .sort()
    .map(k => `${percentEncode(k)}=${percentEncode(oauthParams[k])}`)
    .join('&');

  const signatureBase = [
    method.toUpperCase(),
    percentEncode(url),
    percentEncode(paramString),
  ].join('&');

  const signingKey = `${percentEncode(creds.apiSecret)}&${percentEncode(creds.accessTokenSecret)}`;

  const signature = crypto
    .createHmac('sha1', signingKey)
    .update(signatureBase)
    .digest('base64');

  const allOAuth = { ...oauthParams, oauth_signature: signature };

  return 'OAuth ' + Object.keys(allOAuth)
    .sort()
    .map(k => `${k}="${percentEncode(allOAuth[k])}"`)
    .join(', ');
}

async function postTweet(text, replyToId) {
  const body = { text };
  if (replyToId) {
    body.reply = { in_reply_to_tweet_id: replyToId };
  }

  const authHeader = buildAuthHeader('POST', X_TWEETS_URL, credentials);

  const response = await fetch(X_TWEETS_URL, {
    method: 'POST',
    headers: {
      'Authorization': authHeader,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });

  const data = await response.json();

  if (!response.ok) {
    const msg = (data.errors && data.errors[0] && data.errors[0].message)
      || data.detail
      || data.title
      || `X API error ${response.status}`;
    throw new Error(msg);
  }

  return { id: data.data.id, text: data.data.text };
}

// Post tweets sequentially, each as a reply to the previous
const results = [];
let previousId = null;

for (const text of tweets) {
  const result = await postTweet(text, previousId);
  results.push(result);
  previousId = result.id;
}

return [{
  json: {
    tweets: results,
    id: results[0].id,
    thread_id: results[0].id,
  }
}];

